    string robotWithString(string s) {
        string res = "";
        string t = "";
        for (char c : s) {
            t += c;
            while (!t.empty() && res + t.back() < res + t.substr(1) + t.back()) {
                res += t.back();
                t.pop_back();
            }
        }
        return res + t;
    }
};```
